template<typename T>
T add(T a, T b) { return a + b; }

int main() {
    add(5, 10);            // ✅ Deduced: T = int
    add<double>(5, 10);    // ✅ Forced: T = double, arguments converted
    add<int>(5.5, 10.7);   // ✅ Forced: T = int, 5.5 and 10.7 truncated to 5 and 10
